import React, { useEffect, useState } from 'react';

function App() {
  const [campaigns, setCampaigns] = useState([]);
  // separate filters for id and name (id is exact match)
  const [filters, setFilters] = useState({ id: '', name: '', status: '' });

  const fetchCampaigns = () => {
    const params = new URLSearchParams();
    if (filters.id) params.append('id', filters.id);
    if (filters.name) params.append('name', filters.name);
    if (filters.status) params.append('status', filters.status);

    const qs = params.toString();
    const url = '/api/campaigns' + (qs ? `?${qs}` : '');
    console.log('fetching', url);
    fetch(url)
      .then(res => res.json())
      .then(data => {
        if (data.success) setCampaigns(data.data);
      })
      .catch(console.error);
  };

  useEffect(() => {
    fetchCampaigns();
  }, [filters]);

  const handleChange = e => {
    const { name, value } = e.target;
    setFilters(f => ({ ...f, [name]: value }));
  };

  const clearFilters = () => setFilters({ id: '', name: '', status: '' });

  return (
    <div style={{ padding: 20 }}>
      <h1>Campaigns</h1>
      <div style={{ marginBottom: 20 }}>
        <label>
          ID:{' '}
          <input
            name="id"
            value={filters.id}
            onChange={handleChange}
            placeholder="exact id"
          />
        </label>{' '}
        <label>
          Name:{' '}
          <input
            name="name"
            value={filters.name}
            onChange={handleChange}
            placeholder="contains text"
          />
        </label>{' '}
        <label>
          Status:{' '}
          <select name="status" value={filters.status} onChange={handleChange}>
            <option value="">Any</option>
            <option value="1">Active</option>
            <option value="0">Paused</option>
          </select>
        </label>{' '}
        <button onClick={clearFilters}>Clear</button>
      </div>
      <ul>
        {campaigns.map(c => (
          <li key={c.id}>{c.name} (status: {c.status})</li>
        ))}
      </ul>
    </div>
  );
}

export default App;
